What does this program print?

```cpp
#include <iostream>
template <typename T>
void tag(T v) { std::cout << "generic: " << v << "\n"; }
template <>
void tag<int>(int v) { std::cout << "int: " << v << "\n"; }
int main() {
    tag(3.14);
    tag(42);
    tag('x');
}
```

The programmer wants `describe<bool>` to print `bool: true/false`. But running this program prints `generic: 1` for the bool case. What is the bug?

```cpp
#include <iostream>
template <typename T>
void describe(T v) { std::cout << "generic: " << v << "\n"; }
template <typename T>
void describe<bool>(bool v) {
    std::cout << "bool: " << (v ? "true" : "false") << "\n";
}
int main() {
    describe(true);
}
```

What does this program print?

```cpp
#include <iostream>
template <typename T>
T doubled(T v) { return v * 2; }
template <>
bool doubled<bool>(bool v) { return v; }
int main() {
    std::cout << doubled(5) << "\n";
    std::cout << doubled(true) << "\n";
    std::cout << doubled(false) << "\n";
}
```
